mapper.update:
update outline_scenes
set seq_no = #{seqNo}
where id = #{id}

mapper.select:
select id, project_id, scene_id, seq_no, title, int_ext, location_id, time_of_day,
       purpose_plot, purpose_character, characters_json, source_refs_json, status,
       created_at, updated_at
from outline_scenes
where project_id = #{projectId}
  and scene_id = #{sceneId}
